// modules/notifications/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'notifications',
  description: 'Handles sending notifications to users and persisting them in the database.',

  dependencies: { modules: [] },

  exposes: {
    routes: [
      { method: 'POST', path: '/notifications/send', auth: true, role: 'system' },
    ],
    functions: ['sendNotification'],
    types: ['Notification', 'NotificationError'],
  },

  sideEffects: [
    'writes to: notifications table',
    'sends emails/push notifications',
  ],

  invariants: [
    'Notifications must be sent to valid user IDs',
    'System service accounts are the only ones allowed to send notifications',
  ],
});

